local WindUI = loadstring(game:HttpGet("https://raw.githubusercontent.com/Footagesus/WindUI/main/dist/main.lua"))()

local state = false
local staminaCheckLoop = nil
local noclipEnabled = false
local noclipConnection = nil

local function startStaminaLoop()
    if staminaCheckLoop then
        pcall(function() staminaCheckLoop:disconnect() end)
        staminaCheckLoop = nil
    end
    
    staminaCheckLoop = game:GetService("RunService").Heartbeat:Connect(function()
        if not state then return end
        
        pcall(function()
            local LocalPlayer = game:GetService("Players").LocalPlayer
            if not LocalPlayer or not LocalPlayer.Character then return end
            
            local playerCharacter = LocalPlayer.Character
            local humanoidRootPart = playerCharacter:FindFirstChild("HumanoidRootPart")
            
            if humanoidRootPart then
                local runningUI = humanoidRootPart:FindFirstChild("RunningUI")
                if runningUI then
                    local bars = runningUI:FindFirstChild("Bars")
                    if bars then
                        local staminaBar = bars:FindFirstChild("StaminaBar")
                        if staminaBar then
                            staminaBar.Name = "_StaminaBar"
                        end
                    end
                end
                
                local staminaInfo = playerCharacter:FindFirstChild("Info")
                if staminaInfo then
                    local staminaValue = staminaInfo:FindFirstChild("Stamina")
                    if staminaValue then
                        staminaValue.Value = 150
                    end
                end
            end
        end)
    end)
end

local function stopStaminaLoop()
    if staminaCheckLoop then
        pcall(function() staminaCheckLoop:disconnect() end)
        staminaCheckLoop = nil
    end
end

local function toggleNoclip(value)
    noclipEnabled = value
    
    if noclipConnection then
        noclipConnection:Disconnect()
        noclipConnection = nil
    end
    
    if value then
        noclipConnection = game:GetService("RunService").Stepped:Connect(function()
            if noclipEnabled then
                local character = game.Players.LocalPlayer.Character
                if character then
                    for _, part in pairs(character:GetDescendants()) do
                        if part:IsA("BasePart") then
                            part.CanCollide = false
                        end
                    end
                end
            end
        end)
    else
        local character = game.Players.LocalPlayer.Character
        if character then
            for _, part in pairs(character:GetDescendants()) do
                if part:IsA("BasePart") then
                    part.CanCollide = true
                end
            end
        end
    end
end

local function setupCharacterListeners()
    local LocalPlayer = game:GetService("Players").LocalPlayer
    
    LocalPlayer.CharacterAdded:Connect(function()
        if state then
            task.wait(1)
            startStaminaLoop()
        end
FFG:Toggle("防摔伤", "AntiFallKnockback", false, function(state)
    if state then
        local RunService = game:GetService("RunService")
        local Players = game:GetService("Players")
        local LocalPlayer = Players.LocalPlayer
        local originalGravity = workspace.Gravity
        
        local function setupAntiKnockback(character)
            local humanoidRootPart = character:WaitForChild("HumanoidRootPart")
            local humanoid = character:WaitForChildOfClass("Humanoid")
            
            if not humanoidRootPart or not humanoid then return end
            
            local isFalling = false
            local fallStartTime = 0
            local maxFallSpeed = -30
            local velocityMultiplier = 0.8
            local gravityMultiplier = 0.5
            local groundCheckRay = 6
            
            local function isGrounded()
                local ray = Ray.new(humanoidRootPart.Position, Vector3.new(0, -groundCheckRay, 0))
                local part = workspace:FindPartOnRayWithIgnoreList(ray, {character})
                return part ~= nil
            end
            
            local connection = RunService.Heartbeat:Connect(function()
                if not humanoidRootPart.Parent or humanoid.Health <= 0 then
                    connection:Disconnect()
                    return
                end
                
                local velocity = humanoidRootPart.AssemblyLinearVelocity
                local yVelocity = velocity.Y
                local grounded = isGrounded()
                
                if not grounded and yVelocity < -15 then
                    if not isFalling then
                        isFalling = true
                        fallStartTime = tick()
                    end
                    
                    local fallTime = tick() - fallStartTime
                    
                    if yVelocity < maxFallSpeed then
                        humanoidRootPart.AssemblyLinearVelocity = Vector3.new(
                            velocity.X * velocityMultiplier,
                            maxFallSpeed,
                            velocity.Z * velocityMultiplier
                        )
                    end
                    
                    workspace.Gravity = originalGravity * gravityMultiplier
                    
                    if fallTime > 0.5 then
                        humanoidRootPart.RotVelocity = Vector3.zero
                    end
                    
                    if yVelocity < -60 then
                        humanoidRootPart.AssemblyLinearVelocity = Vector3.new(
                            velocity.X,
                            -35,
                            velocity.Z
                        )
                    end
                elseif grounded then
                    if isFalling then
                        humanoidRootPart.AssemblyLinearVelocity = Vector3.zero
                        humanoidRootPart.AssemblyAngularVelocity = Vector3.zero
                        isFalling = false
                    end
                    workspace.Gravity = originalGravity
                end
                
                if isFalling then
                    humanoid.PlatformStand = false
                    for _, part in pairs(character:GetDescendants()) do
                        if part:IsA("BasePart") then
                            part.CanCollide = false
                        end
                    end
                else
                    for _, part in pairs(character:GetDescendants()) do
                        if part:IsA("BasePart") then
                            part.CanCollide = true
                        end
                    end
                end
            end)
            
            humanoid.StateChanged:Connect(function(_, newState)
                if newState == Enum.HumanoidStateType.Freefall then
                    isFalling = true
                    fallStartTime = tick()
                elseif newState == Enum.HumanoidStateType.Landed then
                    isFalling = false
                    humanoidRootPart.AssemblyLinearVelocity = Vector3.zero
                end
            end)
            
            if not getgenv().AntiKnockbackConnections then
                getgenv().AntiKnockbackConnections = {}
            end
            table.insert(getgenv().AntiKnockbackConnections, connection)
        end
        
        if LocalPlayer.Character then
            setupAntiKnockback(LocalPlayer.Character)
        end
        
        local charConnection = LocalPlayer.CharacterAdded:Connect(setupAntiKnockback)
        if not getgenv().AntiKnockbackConnections then
            getgenv().AntiKnockbackConnections = {}
        end
        table.insert(getgenv().AntiKnockbackConnections, charConnection)
        
    else
        if getgenv().AntiKnockbackConnections then
            for _, conn in ipairs(getgenv().AntiKnockbackConnections) do
                if conn then conn:Disconnect() end
            end
            getgenv().AntiKnockbackConnections = nil
        end
        workspace.Gravity = 196.2
    end
end)
